-- Арка Стеллера — ворота между мирами (Командоры)
UPDATE agent_route_knowledge SET
  updated_at = NOW(), is_visible = TRUE,
  activity_type = 'esoteric',
  title = 'Арка Стеллера — Командорские острова',
  description = 'Арка Стеллера (54.940°N, 166.204°E) — морская скальная арка на Командорских островах, названная в честь Георга Вильгельма Стеллера. Стеллер — натуралист экспедиции Беринга 1741 года, умерший здесь при возвращении в 1746-м. Он был первым европейцем, описавшим природу Берингова моря — и именно здесь оборвалась его жизнь. Командорские острова — физическая точка встречи двух миров: Евразии и Северной Америки. Алеуты, переселённые с Аляски, до сих пор хранят культуру, связывающую Камчатку с Американским континентом. Арка — традиционный символ перехода, «ворота» между мирами. Моржи и сивучи отдыхают на базальте рядом. Долёт из ПК 1,5 часа.'
WHERE id = 'd64e3e6a-72a5-4c14-adc0-588c3824f6ae';

-- Посёлок-призрак Карымский — застывшее время 1996 года
UPDATE agent_route_knowledge SET
